import{_ as o,C as n,o as s,c as l,E as a,w as i,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Romania Healthcare & HRT","description":"Transgender healthcare access in Romania","frontmatter":{"layout":"doc","title":"Romania Healthcare & HRT","description":"Transgender healthcare access in Romania"},"headers":[],"relativePath":"europe/romania/healthcare.md","filePath":"europe/romania/healthcare.md","lastUpdated":null}'),c={name:"europe/romania/healthcare.md"};function h(u,t,m,g,p,b){const e=n("Badge");return s(),l("div",null,[a(e,{variant:"red"},{default:i(()=>[...t[0]||(t[0]=[r("Gatekeeping Model",-1)])]),_:1}),a(e,{variant:"yellow"},{default:i(()=>[...t[1]||(t[1]=[r("Institutul de Endocrinologie",-1)])]),_:1}),a(e,{variant:"yellow"},{default:i(()=>[...t[2]||(t[2]=[r("Limited Services",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="healthcare-hrt-in-romania" tabindex="-1">Healthcare &amp; HRT in Romania <a class="header-anchor" href="#healthcare-hrt-in-romania" aria-label="Permalink to &quot;Healthcare &amp; HRT in Romania&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Romania&#39;s transgender healthcare is <strong>gatekept at a single institute</strong> in Bucharest:</p><ul><li><strong>Psychiatric and endocrinological diagnosis required</strong> for access to HRT</li><li>Primary center: Institutul de Endocrinologie &quot;C.I. Parhon&quot; in Bucharest</li><li>Services concentrated almost entirely in <strong>Bucharest</strong> and <strong>Cluj-Napoca</strong></li><li>Very limited trans-competent providers</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-initial-consultation" tabindex="-1">Step 1: Initial Consultation <a class="header-anchor" href="#step-1-initial-consultation" aria-label="Permalink to &quot;Step 1: Initial Consultation&quot;">​</a></h3><ul><li>Contact <strong>Institutul de Endocrinologie &quot;C.I. Parhon&quot;</strong> in Bucharest</li><li>Psychiatry department for gender dysphoria evaluation</li><li>Some private psychiatrists in Bucharest and Cluj can provide assessments</li><li>Multiple sessions required over several months</li></ul><h3 id="step-2-endocrinology-assessment" tabindex="-1">Step 2: Endocrinology Assessment <a class="header-anchor" href="#step-2-endocrinology-assessment" aria-label="Permalink to &quot;Step 2: Endocrinology Assessment&quot;">​</a></h3><ul><li>Referral to endocrinology department at the same institute</li><li>Baseline blood tests and medical history review</li><li>Discussion of treatment goals</li><li>Diagnosis of gender dysphoria</li></ul><h3 id="step-3-hrt-commencement" tabindex="-1">Step 3: HRT Commencement <a class="header-anchor" href="#step-3-hrt-commencement" aria-label="Permalink to &quot;Step 3: HRT Commencement&quot;">​</a></h3><ul><li>Hormones prescribed after diagnosis and assessment</li><li>Follow-up visits every 3-6 months</li><li>Ongoing monitoring of hormone levels</li><li>Some GPs can manage ongoing care after specialist establishes treatment</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Institutul de Endocrinologie &quot;C.I. Parhon&quot;</td><td>Bucharest</td><td>Comprehensive trans care</td></tr><tr><td>Regina Maria Private Healthcare</td><td>Bucharest, Cluj</td><td>Endocrinology (limited trans experience)</td></tr><tr><td>MedLife Private Healthcare</td><td>Bucharest</td><td>Endocrinology, psychiatry</td></tr><tr><td>Emergency County Hospital</td><td>Cluj-Napoca</td><td>Limited endocrinology</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid in Romania under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be re-evaluated by a Romanian doctor</li><li><strong>Importing medication</strong>: 3-month supply permitted with a doctor&#39;s letter</li><li><strong>Medication availability</strong>: Generally good in major cities</li><li><strong>Pharmacies</strong>: Major chains (Catena, Sensiblu, Help Net) nationwide</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li><strong>No gender-affirming surgeries available</strong> in Romania</li><li>All surgeries require travel abroad</li><li>No public funding for gender-affirming surgery</li><li>Some Romanian surgeons perform top surgery on a private basis (very limited, results vary)</li><li>Bottom surgery: Not available domestically</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Romanian Resident</th><th>Non-Resident</th></tr></thead><tbody><tr><td>Psychiatric assessment (public)</td><td>Free</td><td>Limited access</td></tr><tr><td>Endocrinology visit (public)</td><td>Free</td><td>Limited access</td></tr><tr><td>Private psychiatric assessment</td><td>€40-80</td><td>€40-80</td></tr><tr><td>Private endocrinology</td><td>€40-70</td><td>€40-70</td></tr><tr><td>HRT (monthly)</td><td>€10-25</td><td>€15-35</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.endocrinobucuresti.ro/" target="_blank" rel="noreferrer">Institutul de Endocrinologie &quot;C.I. Parhon&quot;</a></li><li><a href="https://acceptromania.ro/" target="_blank" rel="noreferrer">ACCEPT (LGBTQ+ Organization)</a></li><li><a href="https://www.ms.ro/" target="_blank" rel="noreferrer">Romanian Ministry of Health</a></li><li><a href="https://www.cnas.ro/" target="_blank" rel="noreferrer">CNAS (National Health Insurance House)</a></li></ul>',21))])}const v=o(c,[["render",h]]);export{f as __pageData,v as default};
